class Solution:
    def maxSum(self, nums: List[int]) -> int:
        from collections import defaultdict

        # Group numbers by their maximum digit
        groups = defaultdict(list)
        for num in nums:
            max_digit = max(int(d) for d in str(num))
            groups[max_digit].append(num)

        # Find the maximum sum for each group
        max_total = -1
        for group in groups.values():
            if len(group) >= 2:
                # Sort to get the two largest numbers
                group.sort()
                current_sum = group[-1] + group[-2]
                if current_sum > max_total:
                    max_total = current_sum

        return max_total
